def match_parens(lst):
    s1 = lst[0]
    s2 = lst[1]

    # Check if total open parentheses equals total close parentheses
    if (s1.count('(') + s2.count('(')) != (s1.count(')') + s2.count(')')):
        return 'No'

    def is_good(s):
        balance = 0
        for char in s:
            if char == '(':
                balance += 1
            elif char == ')':
                balance -= 1

            # If balance drops below zero, it's invalid
            if balance < 0:
                return False

        # Must return to zero at the end
        return balance == 0

    # Check both concatenation orders
    if is_good(s1 + s2) or is_good(s2 + s1):
        return 'Yes'
    else:
        return 'No'

