def prod_signs(arr):
    if not arr:
        return None

    sum_magnitudes = 0
    product_signs = 1

    for num in arr:
        sum_magnitudes += abs(num)

        if num > 0:
            sign = 1
        elif num < 0:
            sign = -1
        else:
            sign = 0

        product_signs *= sign

