def minPath(grid, k):
    N = len(grid)
    start_i = start_j = 0
    found = False
    for i in range(N):
        for j in range(N):
            if grid[i][j] == 1:
                start_i, start_j = i, j
                found = True
                break
        if found:
            break
    path = [1]
    current_i, current_j = start_i, start_j
    for _ in range(k-1):
        best_val = float('inf')
        best_pos = None
        for dx, dy in [(0,1), (0,-1), (1,0), (-1,0)]:
            ni, nj = current_i + dx, current_j + dy
            if 0 <= ni < N and 0 <= nj < N:
                if grid[ni][nj] < best_val:
                    best_val = grid[ni][nj]
                    best_pos = (ni, nj)
        path.append(best_val)
        current_i, current_j = best_pos
    return path

