def get_max_triples(n):
    # Calculate the count of indices where (i*i - i + 1) % 3 == 0
    # Analysis shows this happens when i % 3 == 2
    # The count of such indices in range [1, n] is (n + 1) // 3
    count0 = (n + 1) // 3
    count1 = n - count0

    def combinations_of_3(k):
        if k < 3:
            return 0
        return k * (k - 1) * (k - 2) // 6

    # We need either three remainders of 0 or three remainders of 1
    # because 0+0+0=0 and 1+1+1=3 (both mod 3)
    return combinations_of_3(count0) + combinations_of_3(count1)

