def encrypt(s):
    result = []
    shift = 4
    for char in s:
        if 'a' <= char <= 'z':
            result.append(chr((ord(char) - ord('a') + shift) % 26 + ord('a')))
        elif 'A' <= char <= 'Z':
            result.append(chr((ord(char) - ord('A') + shift) % 26 + ord('A')))
        else:
            result.append(char)
    return "".join(result)

def encode(message):
    result = []
    for char in message:
        if not char.isalpha():
            # Preserve non-alphabetic characters (spaces, digits, punctuation)
            result.append(char)
        else:
            # Check if character is a vowel (case insensitive check)
            if char.lower() in 'aeiou':
                # Vowels: convert to lowercase and shift
                lower_char = char.lower()
                if lower_char == 'o':
                    # 'o' shifts by -2 to 'm'
                    shifted = chr(ord(lower_char) - 2)
                else:
                    # Other vowels shift by +2
                    shifted = chr(ord(lower_char) + 2)
                result.append(shifted)
            else:
                # Non-vowel letters: preserve original character as-is
                result.append(char)
    return ''.join(result)
